------------------------------------------------------------
----- ROOT ID FUNCTION FOR: [Course].[PrerequisiteCourseID]
------------------------------------------------------------
IF OBJECT_ID('[AssociationDemo].[fnCoursePrerequisiteCourseID_GetRootID]', 'IF') IS NOT NULL
    DROP FUNCTION [AssociationDemo].[fnCoursePrerequisiteCourseID_GetRootID];
GO

CREATE FUNCTION [AssociationDemo].[fnCoursePrerequisiteCourseID_GetRootID]
(
    @RecordID uniqueidentifier,
    @ParentID uniqueidentifier
)
RETURNS TABLE
AS
RETURN
(
    WITH CTE_RootParent AS (
        SELECT
            [ID],
            [PrerequisiteCourseID],
            [ID] AS [RootParentID],
            0 AS [Depth]
        FROM
            [AssociationDemo].[Course]
        WHERE
            [ID] = COALESCE(@ParentID, @RecordID)

        UNION ALL

        SELECT
            c.[ID],
            c.[PrerequisiteCourseID],
            c.[ID] AS [RootParentID],
            p.[Depth] + 1 AS [Depth]
        FROM
            [AssociationDemo].[Course] c
        INNER JOIN
            CTE_RootParent p ON c.[ID] = p.[PrerequisiteCourseID]
        WHERE
            p.[Depth] < 100
    )
    SELECT TOP 1
        [RootParentID] AS RootID
    FROM
        CTE_RootParent
    WHERE
        [PrerequisiteCourseID] IS NULL
    ORDER BY
        [RootParentID]
);
GO


