------------------------------------------------------------
IF OBJECT_ID('[AssociationDemo].[fnForumCategoryParentCategoryID_GetRootID]', 'IF') IS NOT NULL
    DROP FUNCTION [AssociationDemo].[fnForumCategoryParentCategoryID_GetRootID];
GO

CREATE FUNCTION [AssociationDemo].[fnForumCategoryParentCategoryID_GetRootID]
(
    @RecordID uniqueidentifier,
    @ParentID uniqueidentifier
)
RETURNS TABLE
AS
RETURN
(
    WITH CTE_RootParent AS (
        SELECT
            [ID],
            [ParentCategoryID],
            [ID] AS [RootParentID],
            0 AS [Depth]
        FROM
            [AssociationDemo].[ForumCategory]
        WHERE
            [ID] = COALESCE(@ParentID, @RecordID)

        UNION ALL

        SELECT
            c.[ID],
            c.[ParentCategoryID],
            c.[ID] AS [RootParentID],
            p.[Depth] + 1 AS [Depth]
        FROM
            [AssociationDemo].[ForumCategory] c
        INNER JOIN
            CTE_RootParent p ON c.[ID] = p.[ParentCategoryID]
        WHERE
            p.[Depth] < 100
    )
    SELECT TOP 1
        [RootParentID] AS RootID
    FROM
        CTE_RootParent
    WHERE
        [ParentCategoryID] IS NULL
    ORDER BY
        [RootParentID]
);
GO


