------------------------------------------------------------
----- ROOT ID FUNCTION FOR: [ForumPost].[ParentPostID]
------------------------------------------------------------
IF OBJECT_ID('[AssociationDemo].[fnForumPostParentPostID_GetRootID]', 'IF') IS NOT NULL
    DROP FUNCTION [AssociationDemo].[fnForumPostParentPostID_GetRootID];
GO

CREATE FUNCTION [AssociationDemo].[fnForumPostParentPostID_GetRootID]
(
    @RecordID uniqueidentifier,
    @ParentID uniqueidentifier
)
RETURNS TABLE
AS
RETURN
(
    WITH CTE_RootParent AS (
        SELECT
            [ID],
            [ParentPostID],
            [ID] AS [RootParentID],
            0 AS [Depth]
        FROM
            [AssociationDemo].[ForumPost]
        WHERE
            [ID] = COALESCE(@ParentID, @RecordID)

        UNION ALL

        SELECT
            c.[ID],
            c.[ParentPostID],
            c.[ID] AS [RootParentID],
            p.[Depth] + 1 AS [Depth]
        FROM
            [AssociationDemo].[ForumPost] c
        INNER JOIN
            CTE_RootParent p ON c.[ID] = p.[ParentPostID]
        WHERE
            p.[Depth] < 100
    )
    SELECT TOP 1
        [RootParentID] AS RootID
    FROM
        CTE_RootParent
    WHERE
        [ParentPostID] IS NULL
    ORDER BY
        [RootParentID]
);
GO


